import { useLocation, useNavigate } from "react-router-dom";
import { useState, useMemo } from "react";
import logo from "../assets/logo.png";

export default function Checkout() {
  const location = useLocation();
  const navigate = useNavigate();

  const cart = Array.isArray(location.state?.cart) ? location.state.cart : [];

  const [form, setForm] = useState({
    name: "",
    email: "",
    address: "",
    cardHolder: "",
    cardType: "visa",
    cardNumber: "",
    cvv: "",
    expiry: "",
  });

  const total = useMemo(() => {
    return cart.reduce((sum, item) => {
      const price = Number(item?.price || 0);
      const qty = Number(item?.qty || 0);
      return sum + price * qty;
    }, 0);
  }, [cart]);

  const handleChange = (e) => {
    setForm((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleSubmit = () => {
    alert("Compra realizada");
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <div style={styles.header}>
          <img src={logo} alt="logo" style={styles.logo} />
          <h2>Checkout</h2>
          <p style={styles.subtitle}>Verifica y paga tus productos aquí.</p>
        </div>

        <div style={styles.grid}>
          <div style={styles.cart}>
            <h3>Productos</h3>

            {cart.length === 0 ? (
              <p>No hay productos en el carrito.</p>
            ) : (
              <>
                <div style={styles.cartList}>
                  {cart.map((item, index) => (
                    <div key={item.id || index} style={styles.row}>
                      <span>
                        {item.name} x {item.qty}
                      </span>
                      <span>
                        $
                        {(
                          Number(item.price || 0) * Number(item.qty || 0)
                        ).toFixed(2)}
                      </span>
                    </div>
                  ))}
                </div>

                <h3>Total: ${total.toFixed(2)}</h3>
              </>
            )}
          </div>

          <div style={styles.form}>
            <h3>Datos de pago</h3>

            <input
              name="name"
              placeholder="Nombre"
              onChange={handleChange}
              style={styles.input}
            />
            <input
              name="email"
              placeholder="Email"
              onChange={handleChange}
              style={styles.input}
            />
            <input
              name="address"
              placeholder="Dirección"
              onChange={handleChange}
              style={styles.input}
            />

            <input
              name="cardHolder"
              placeholder="Titular de la tarjeta"
              onChange={handleChange}
              style={styles.input}
            />

            <select
              name="cardType"
              onChange={handleChange}
              style={styles.input}
            >
              <option value="visa">Visa</option>
              <option value="mastercard">MasterCard</option>
              <option value="amex">Amex</option>
            </select>

            <input
              name="cardNumber"
              placeholder="Número de tarjeta"
              onChange={handleChange}
              style={styles.input}
            />
            <input
              name="cvv"
              placeholder="CVV"
              onChange={handleChange}
              style={styles.input}
            />
            <input
              name="expiry"
              placeholder="MM/AA"
              onChange={handleChange}
              style={styles.input}
            />

            <button onClick={handleSubmit} style={styles.button}>
              Confirmar compra
            </button>

            <button
              onClick={() => navigate("/tienda")}
              style={styles.secondary}
            >
              Volver
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    background: "#f5f7fb",
    padding: "2rem 1rem",
  },

  container: {
    maxWidth: "1100px",
    margin: "0 auto",
  },

  header: {
    textAlign: "center",
    marginBottom: "2rem",
  },

  logo: {
    width: "120px",
  },

  subtitle: {
    color: "#64748b",
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: "2rem",
  },

  cart: {
    background: "white",
    padding: "1.5rem",
    borderRadius: "12px",
    boxShadow: "0 10px 30px rgba(0,0,0,0.1)",
    height: "fit-content",
  },

  form: {
    background: "white",
    padding: "1.5rem",
    borderRadius: "12px",
    boxShadow: "0 10px 30px rgba(0,0,0,0.1)",
    display: "flex",
    flexDirection: "column",
    gap: "10px",
  },

  cartList: {
    maxHeight: "250px",
    overflowY: "auto",
    marginBottom: "1rem",
  },

  row: {
    display: "flex",
    justifyContent: "space-between",
    marginBottom: "6px",
  },

  input: {
    padding: "10px",
    borderRadius: "8px",
    border: "1px solid #ddd",
  },

  button: {
    marginTop: "1rem",
    padding: "10px",
    background: "#32d5d5",
    border: "none",
    borderRadius: "8px",
    color: "white",
    cursor: "pointer",
  },

  secondary: {
    marginTop: "10px",
    padding: "10px",
    background: "#e2e8f0",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer",
  },
};
